@Configuration
public class ElasticsearchConfig {

    @Bean(destroyMethod = "close")
    public RestHighLevelClient restHighLevelClient(
            @Value("${elasticsearch.hosts:localhost:9200}") String hostsCsv,
            @Value("${elasticsearch.scheme:http}") String scheme
    ) {
        String[] parts = hostsCsv.split(",");
        List<HttpHost> hosts = new ArrayList<>();
        for (String p : parts) {
            String s = p.trim();
            if (s.isEmpty()) continue;
            String host = s;
            int port = 9200;
            if (s.contains(":")) {
                String[] hp = s.split(":");
                host = hp[0].trim();
                port = Integer.parseInt(hp[1].trim());
            }
            hosts.add(new HttpHost(host, port, scheme));
        }
        return new RestHighLevelClient(RestClient.builder(hosts.toArray(new HttpHost[0])));
    }
}

