package com.example.search.service;

import com.example.search.model.Product;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.ElasticsearchStatusException;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.support.WriteRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.client.indices.PutMappingRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.List;
import java.util.Map;

@Service
public class ProductIndexService {

    private final RestHighLevelClient client;
    private final ObjectMapper mapper;

    private final String indexName;

    public ProductIndexService(RestHighLevelClient client,
                               ObjectMapper mapper,
                               @Value("${elasticsearch.index.products:products}") String indexName) {
        this.client = client;
        this.mapper = mapper;
        this.indexName = indexName;
    }

    public String getIndexName() {
        return indexName;
    }

    public void ensureIndex() throws IOException {
        GetIndexRequest get = new GetIndexRequest(indexName);
        boolean exists = client.indices().exists(get, RequestOptions.DEFAULT);
        if (exists) return;

        CreateIndexRequest create = new CreateIndexRequest(indexName);
        create.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0)
        );

        String mapping = "{\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"keyword\"},\n" +
                "    \"sku\": {\"type\": \"keyword\"},\n" +
                "    \"name\": {\"type\": \"text\", \"analyzer\": \"standard\", \"fields\": {\"keyword\": {\"type\":\"keyword\",\"ignore_above\":256}}},\n" +
                "    \"description\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                "    \"brand\": {\"type\": \"keyword\"},\n" +
                "    \"categories\": {\"type\": \"keyword\"},\n" +
                "    \"tags\": {\"type\": \"keyword\"},\n" +
                "    \"price\": {\"type\": \"double\"},\n" +
                "    \"currency\": {\"type\": \"keyword\"},\n" +
                "    \"stock\": {\"type\": \"integer\"},\n" +
                "    \"rating\": {\"type\": \"double\"},\n" +
                "    \"attributes\": {\"type\": \"flattened\"},\n" +
                "    \"createdAt\": {\"type\": \"date\"},\n" +
                "    \"updatedAt\": {\"type\": \"date\"}\n" +
                "  }\n" +
                "}";
        create.mapping(mapping, XContentType.JSON);
        client.indices().create(create, RequestOptions.DEFAULT);
    }

    public void putMappingUpdateIfNeeded(Map<String, Object> partialMapping) throws IOException {
        PutMappingRequest req = new PutMappingRequest(indexName);
        req.source(partialMapping);
        client.indices().putMapping(req, RequestOptions.DEFAULT);
    }

    public void deleteIndex() throws IOException {
        try {
            client.indices().delete(new DeleteIndexRequest(indexName), RequestOptions.DEFAULT);
        } catch (ElasticsearchStatusException e) {
            // ignore
        }
    }

    public void indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isBlank()) {
            throw new IllegalArgumentException("Product id is required");
        }
        Instant now = Instant.now();
        if (product.getCreatedAt() == null) product.setCreatedAt(now);
        product.setUpdatedAt(now);

        IndexRequest req = new IndexRequest(indexName)
                .id(product.getId())
                .source(mapper.convertValue(product, Map.class))
                .setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL);
        client.index(req, RequestOptions.DEFAULT);
    }

    public BulkResponse bulkIndex(List<Product> products) throws IOException {
        BulkRequest bulk = new BulkRequest();
        Instant now = Instant.now();
        for (Product p : products) {
            if (p.getId() == null || p.getId().isBlank()) continue;
            if (p.getCreatedAt() == null) p.setCreatedAt(now);
            p.setUpdatedAt(now);
            bulk.add(new IndexRequest(indexName)
                    .id(p.getId())
                    .source(mapper.convertValue(p, Map.class)));
        }
        bulk.setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL);
        return client.bulk(bulk, RequestOptions.DEFAULT);
    }
}

package com.example.search.service;

import com.example.search.dto.SearchRequestDto;
import com.example.search.dto.SearchResponseDto;
import com.example.search.model.Product;
import com.example.search.model.SearchQueryLog;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.action.support.WriteRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.Operator;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortBuilders;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;

@Service
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final ObjectMapper mapper;
    private final ProductIndexService productIndexService;
    private final SearchQueryLogService queryLogService;
    private final String productsIndex;

    public ProductSearchService(RestHighLevelClient client,
                                ObjectMapper mapper,
                                ProductIndexService productIndexService,
                                SearchQueryLogService queryLogService,
                                @Value("${elasticsearch.index.products:products}") String productsIndex) {
        this.client = client;
        this.mapper = mapper;
        this.productIndexService = productIndexService;
        this.queryLogService = queryLogService;
        this.productsIndex = productsIndex;
    }

    public SearchResponseDto search(SearchRequestDto req, String userId, String sessionId, String ip) throws IOException {
        productIndexService.ensureIndex();

        int page = Math.max(0, req.getPage());
        int size = Math.min(200, Math.max(1, req.getSize()));
        int from = page * size;

        BoolQueryBuilder bool = QueryBuilders.boolQuery();

        String q = req.getQ() == null ? "" : req.getQ().trim();
        if (!q.isEmpty()) {
            MultiMatchQueryBuilder mm = QueryBuilders.multiMatchQuery(q, "name^4", "description^1", "brand^2", "tags^2")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .operator(Operator.AND)
                    .fuzziness("AUTO");
            bool.must(mm);
        } else {
            bool.must(QueryBuilders.matchAllQuery());
        }

        if (req.getCategories() != null && !req.getCategories().isEmpty()) {
            bool.filter(QueryBuilders.termsQuery("categories", req.getCategories()));
        }
        if (req.getBrands() != null && !req.getBrands().isEmpty()) {
            bool.filter(QueryBuilders.termsQuery("brand", req.getBrands()));
        }
        if (req.getMinPrice() != null || req.getMaxPrice() != null) {
            var range = QueryBuilders.rangeQuery("price");
            if (req.getMinPrice() != null) range.gte(req.getMinPrice());
            if (req.getMaxPrice() != null) range.lte(req.getMaxPrice());
            bool.filter(range);
        }

        if (req.getAttributes() != null && !req.getAttributes().isEmpty()) {
            for (Map.Entry<String, List<String>> e : req.getAttributes().entrySet()) {
                String key = e.getKey();
                List<String> values = e.getValue();
                if (key == null || key.isBlank() || values == null || values.isEmpty()) continue;
                String field = "attributes." + key;
                bool.filter(QueryBuilders.termsQuery(field, values));
            }
        }

        SearchSourceBuilder source = new SearchSourceBuilder()
                .query(bool)
                .from(from)
                .size(size)
                .trackTotalHits(true);

        addSorting(req, source);

        source.aggregation(AggregationBuilders.terms("facet_categories").field("categories").size(50));
        source.aggregation(AggregationBuilders.terms("facet_brands").field("brand").size(50));
        source.aggregation(AggregationBuilders.terms("facet_tags").field("tags").size(50));

        SearchRequest sreq = new SearchRequest(productsIndex);
        sreq.source(source);

        SearchResponse resp = client.search(sreq, RequestOptions.DEFAULT);

        List<Product> items = new ArrayList<>();
        for (SearchHit hit : resp.getHits().getHits()) {
            Map<String, Object> m = hit.getSourceAsMap();
            if (m == null) continue;
            Product p = mapper.convertValue(m, Product.class);
            if (p.getId() == null) p.setId(hit.getId());
            items.add(p);
        }

        Map<String, Map<String, Long>> facets = new LinkedHashMap<>();
        facets.put("categories", termsToFacet((Terms) resp.getAggregations().get("facet_categories")));
        facets.put("brands", termsToFacet((Terms) resp.getAggregations().get("facet_brands")));
        facets.put("tags", termsToFacet((Terms) resp.getAggregations().get("facet_tags")));

        long total = resp.getHits().getTotalHits() == null ? items.size() : resp.getHits().getTotalHits().value;

        SearchQueryLog log = new SearchQueryLog();
        log.setId(UUID.randomUUID().toString());
        log.setQuery(q);
        log.setFilters(buildFilterMap(req));
        log.setUserId(userId);
        log.setSessionId(sessionId);
        log.setIp(ip);
        log.setTimestamp(Instant.now());
        log.setTotalHits((int) Math.min(Integer.MAX_VALUE, total));
        queryLogService.indexLog(log);

        return new SearchResponseDto(total, page, size, items, facets);
    }

    private static Map<String, Map<String, Long>> emptyFacets() {
        Map<String, Map<String, Long>> facets = new LinkedHashMap<>();
        facets.put("categories", new LinkedHashMap<>());
        facets.put("brands", new LinkedHashMap<>());
        facets.put("tags", new LinkedHashMap<>());
        return facets;
    }

    private Map<String, Object> buildFilterMap(SearchRequestDto req) {
        Map<String, Object> filters = new LinkedHashMap<>();
        if (req.getCategories() != null && !req.getCategories().isEmpty()) filters.put("categories", req.getCategories());
        if (req.getBrands() != null && !req.getBrands().isEmpty()) filters.put("brands", req.getBrands());
        if (req.getMinPrice() != null) filters.put("minPrice", req.getMinPrice());
        if (req.getMaxPrice() != null) filters.put("maxPrice", req.getMaxPrice());
        if (req.getAttributes() != null && !req.getAttributes().isEmpty()) filters.put("attributes", req.getAttributes());
        if (req.getSort() != null && !req.getSort().isBlank()) filters.put("sort", req.getSort());
        if (req.getPage() != null) filters.put("page", req.getPage());
        if (req.getSize() != null) filters.put("size", req.getSize());
        return filters;
    }

    private Map<String, Long> termsToFacet(Terms terms) {
        Map<String, Long> m = new LinkedHashMap<>();
        if (terms == null) return m;
        for (Terms.Bucket b : terms.getBuckets()) {
            m.put(b.getKeyAsString(), b.getDocCount());
        }
        return m;
    }

    private void addSorting(SearchRequestDto req, SearchSourceBuilder source) {
        String sort = req.getSort() == null ? "" : req.getSort().trim();
        if (sort.isEmpty() || sort.equalsIgnoreCase("relevance")) {
            return;
        }
        switch (sort.toLowerCase(Locale.ROOT)) {
            case "price_asc":
                source.sort(SortBuilders.fieldSort("price").order(SortOrder.ASC));
                break;
            case "price_desc":
                source.sort(SortBuilders.fieldSort("price").order(SortOrder.DESC));
                break;
            case "rating_desc":
                source.sort(SortBuilders.fieldSort("rating").order(SortOrder.DESC));
                break;
            case "newest":
                source.sort(SortBuilders.fieldSort("createdAt").order(SortOrder.DESC));
                break;
            default:
                break;
        }
    }
}

package com.example.search.service;

import com.example.search.model.SearchQueryLog;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.util.Map;

@Service
public class SearchQueryLogService {

    private final RestHighLevelClient client;
    private final ObjectMapper mapper;
    private final String indexName;

    public SearchQueryLogService(RestHighLevelClient client,
                                ObjectMapper mapper,
                                @Value("${elasticsearch.index.search_logs:search_queries}") String indexName) {
        this.client = client;
        this.mapper = mapper;
        this.indexName = indexName;
    }

    public void ensureIndex() throws IOException {
        boolean exists = client.indices().exists(new GetIndexRequest(indexName), RequestOptions.DEFAULT);
        if (exists) return;

        CreateIndexRequest create = new CreateIndexRequest(indexName);
        create.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0)
        );

        String mapping = "{\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"keyword\"},\n" +
                "    \"query\": {\"type\": \"text\", \"fields\": {\"keyword\": {\"type\":\"keyword\",\"ignore_above\":512}}},\n" +
                "    \"filters\": {\"type\": \"flattened\"},\n" +
                "    \"userId\": {\"type\": \"keyword\"},\n" +
                "    \"sessionId\": {\"type\": \"keyword\"},\n" +
                "    \"ip\": {\"type\": \"ip\"},\n" +
                "    \"timestamp\": {\"type\": \"date\"},\n" +
                "    \"totalHits\": {\"type\": \"integer\"}\n" +
                "  }\n" +
                "}";
        create.mapping(mapping, XContentType.JSON);

        client.indices().create(create, RequestOptions.DEFAULT);
    }

    public void indexLog(SearchQueryLog log) throws IOException {
        ensureIndex();
        if (log.getId() == null || log.getId().isBlank()) {
            throw new IllegalArgumentException("Log id is required");
        }
        IndexRequest req = new IndexRequest(indexName)
                .id(log.getId())
                .source(mapper.convertValue(log, Map.class));
        client.index(req, RequestOptions.DEFAULT);
    }
}

package com.example.search.controller;

import com.example.search.dto.SearchRequestDto;
import com.example.search.dto.SearchResponseDto;
import com.example.search.model.Product;
import com.example.search.service.ProductIndexService;
import com.example.search.service.ProductSearchService;
import org.elasticsearch.action.bulk.BulkResponse;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import jakarta.servlet.http.HttpServletRequest;
import java.io.IOException;
import java.util.List;

@RestController
@RequestMapping("/api")
public class ProductSearchController {

    private final ProductIndexService indexService;
    private final ProductSearchService searchService;

    public ProductSearchController(ProductIndexService indexService, ProductSearchService searchService) {
        this.indexService = indexService;
        this.searchService = searchService;
    }

    @PostMapping("/products")
    public ResponseEntity<?> indexProduct(@RequestBody Product product) throws IOException {
        indexService.ensureIndex();
        indexService.indexProduct(product);
        return ResponseEntity.status(HttpStatus.CREATED).build();
    }

    @PostMapping("/products/_bulk")
    public ResponseEntity<?> bulkIndex(@RequestBody List<Product> products) throws IOException {
        indexService.ensureIndex();
        BulkResponse resp = indexService.bulkIndex(products);
        if (resp.hasFailures()) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(resp.buildFailureMessage());
        }
        return ResponseEntity.status(HttpStatus.CREATED).build();
    }

    @PostMapping("/search")
    public SearchResponseDto search(@RequestBody SearchRequestDto request,
                                   @RequestHeader(value = "X-User-Id", required = false) String userId,
                                   @RequestHeader(value = "X-Session-Id", required = false) String sessionId,
                                   HttpServletRequest http) throws IOException {
        String ip = extractIp(http);
        return searchService.search(request, userId, sessionId, ip);
    }

    private String extractIp(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isBlank()) {
            return xff.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

